<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class FleetController{
 public function index():void{Auth::requireRole('owner','office','crew_leader');$rows=Database::connection()->query('SELECT * FROM vehicles ORDER BY unit_number')->fetchAll();View::render('portal/fleet/index',['title'=>'Fleet','vehicles'=>$rows],'portal');}
 public function store():void{Auth::requireRole('owner','office');verify_csrf();$s=Database::connection()->prepare('INSERT INTO vehicles(unit_number,year,make,model,vin,plate,status,odometer,next_service_date,notes) VALUES(?,?,?,?,?,?,?,?,?,?)');$s->execute([trim($_POST['unit_number']),$_POST['year']?:null,trim($_POST['make']??''),trim($_POST['model']??''),trim($_POST['vin']??''),trim($_POST['plate']??''),$_POST['status']??'active',$_POST['odometer']?:null,$_POST['next_service_date']?:null,trim($_POST['notes']??'')]);$id=(int)Database::connection()->lastInsertId();Database::connection()->prepare('UPDATE vehicles SET asset_tag=?,qr_token=? WHERE id=?')->execute(['RB-VEH-'.str_pad((string)$id,4,'0',STR_PAD_LEFT),bin2hex(random_bytes(16)),$id]);AuditService::log('vehicle.created','vehicle',$id);flash('success','Vehicle added.');redirect('/portal/fleet');}
 public function update(string $id):void{Auth::requireRole('owner','office');verify_csrf();$s=Database::connection()->prepare('UPDATE vehicles SET unit_number=?,year=?,make=?,model=?,vin=?,plate=?,status=?,odometer=?,next_service_date=?,notes=? WHERE id=?');$s->execute([trim($_POST['unit_number']),$_POST['year']?:null,trim($_POST['make']??''),trim($_POST['model']??''),trim($_POST['vin']??''),trim($_POST['plate']??''),$_POST['status']??'active',$_POST['odometer']?:null,$_POST['next_service_date']?:null,trim($_POST['notes']??''),(int)$id]);flash('success','Vehicle updated.');redirect('/portal/fleet');}
}
